for(int i = -4; i <= 5; ++i) {
	draw((i,-1)--(i,6), dashed+mediumgrey);
}

for(int i = 1; i <= 6; ++i) {
	draw((-4,i)--(5,i), dashed+mediumgrey);
}

Label laxis; laxis.p=fontsize(10);

